/**
 * @param {number} n
 * @param {number} pos
 * @param {number} k
 * @return {number}
 */
function solve(n, pos, k) {
    const MOD = 10**9 + 7;

    // Number of people to the left of pos (indices 0 to pos-1)
    const leftCount = pos;
    // Number of people to the right of pos (indices pos+1 to n-1)
    const rightCount = n - 1 - pos;

    // The person at 'pos' can choose 'L' or 'R' independently, contributing a factor of 2 to the final answer.
    let multiplier = 2;

    // The visibility rules:
    // 1. i < pos: visible iff person i chooses 'L'. (Count depends on left choices)
    // 2. i > pos: visible iff person i chooses 'R'. (Count depends on right choices)

    // We need to choose 'l_visible' people from the leftCount who choose 'L',
    // and 'r_visible' people from the rightCount who choose 'R', such that:
    // l_visible + r_visible = k

    // Total ways = sum_{l_visible = 0}^{k} [ C(leftCount, l_visible) * C(rightCount, k - l_visible) ] * multiplier

    // Precompute factorials and inverse factorials for combinations C(n, k)
    const MAX_N = n;
    const fact = new Array(MAX_N + 1);
    const invFact = new Array(MAX_N + 1);

    fact[0] = 1;
    for (let i = 1; i <= MAX_N; i++) {
        fact[i] = (fact[i - 1] * i) % MOD;
    }

    // Modular exponentiation (a^b % m)
    const power = (base, exp) => {
        let res = 1;
        base %= MOD;
        while (exp > 0) {
            if (exp % 2 === 1) res = (res * base) % MOD;
            base = (base * base) % MOD;
            exp = Math.floor(exp / 2);
        }
        return res;
    };

    // Modular inverse using Fermat's Little Theorem: a^(MOD-2) % MOD
    const modInverse = (n) => power(n, MOD - 2);

    invFact[MAX_N] = modInverse(fact[MAX_N]);
    for (let i = MAX_N - 1; i >= 0; i--) {
        invFact[i] = (invFact[i + 1] * (i + 1)) % MOD;
    }

    // Combination function C(n, k) % MOD
    const combinations = (N, K) => {
        if (K < 0 || K > N) {
            return 0;
        }
        if (K === 0 || K === N) {
            return 1;
        }
        if (K > N / 2) {
            K = N - K;
        }
        // C(N, K) = N! / (K! * (N-K)!)
        let res = fact[N];
        res = (res * invFact[K]) % MOD;
        res = (res * invFact[N - K]) % MOD;
        return res;
    };

    let totalWaysSum = 0;

    // Iterate over the number of visible people from the left (l_visible)
    // l_visible must be between 0 and leftCount.
    // r_visible = k - l_visible must be between 0 and rightCount.
    for (let l_visible = 0; l_visible <= leftCount; l_visible++) {
        const r_visible = k - l_visible;

        if (r_visible >= 0 && r_visible <= rightCount) {
            // Ways to choose l_visible from leftCount: C(leftCount, l_visible)
            const waysLeft = combinations(leftCount, l_visible);

            // Ways to choose r_visible from rightCount: C(rightCount, r_visible)
            const waysRight = combinations(rightCount, r_visible);

            // Contribution for this split: waysLeft * waysRight
            let contribution = (waysLeft * waysRight) % MOD;

            totalWaysSum = (totalWaysSum + contribution) % MOD;
        }
    }

    // Final answer = totalWaysSum * multiplier (for pos's choice)
    const finalAnswer = (totalWaysSum * multiplier) % MOD;

    return finalAnswer;
}

